@function breakpoint-next(
  $name,
  $breakpoints: $grid-breakpoints,
  $breakpoint-names: map.keys($breakpoints)
) {
  $n: list.index($breakpoint-names, $name);
  @if $n != null and $n < list.length($breakpoint-names) {
    @return list.nth($breakpoint-names, $n + 1);
  }
  @return null;
}

@function breakpoint-prev(
  $name,
  $breakpoints: $grid-breakpoints,
  $breakpoint-names: map.keys($breakpoints)
) {
  $n: list.index($breakpoint-names, $name);
  @if $n != null and $n > 1 {
    @return list.nth($breakpoint-names, $n - 1);
  }
  @return null;
}

@else if map.has-key($breakpoints, $name) {
  $breakpoint: map.get($breakpoints, $name);
  $width: map.get($breakpoint, width);
  @if is-smallest-breakpoint($name, $breakpoints) {
    @content;
  } @else {
    @media (min-width: $width) {
      @content;
    }
  }
}

@if $min and $max {
  $min-width: $min;
  $max-width: $max;

  @if not $is-number-lower and meta.type-of($min) == 'map' {
    $min-width: map.get($min, width);
  }

  @if not $is-number-upper and meta.type-of($max) == 'map' {
    $max-width: map.get($max, width);
  }

  @media (min-width: $min-width) and (max-width: $max-width) {
    @content;
  }
}

@for $i from 0 through get-column-count($breakpoints, $name) {
  @if is-smallest-breakpoint($name, $breakpoints) {
    .#{$prefix}--#{$name}\:col-span-#{$i} {
      @include -column-span($i);
    }
  } @else {
    @include breakpoint($name) {
      .#{$prefix}--#{$name}\:col-span-#{$i} {
        @include -column-span($i);
      }
    }
  }
}

@else {
  $previous-breakpoint: breakpoint-prev($key, $breakpoints);
  $previous-column-count: get-column-count(
    $breakpoints,
    $previous-breakpoint
  );
  $previous-span: $previous-column-count * $percent;

  @if $span != $previous-span {
    @include breakpoint($key) {
      --cds-grid-columns: #{$span};

      grid-column: span list.slash($span, span) #{$span};
    }
  }
}

@mixin -no-gutter {
  .#{$prefix}--no-gutter,
  .#{$prefix}--row.#{$prefix}--no-gutter [class*='#{$prefix}--col'] {
    padding-inline: 0;
  }

  .#{$prefix}--no-gutter--start,
  .#{$prefix}--row.#{$prefix}--no-gutter--start [class*='#{$prefix}--col'] {
    padding-inline-start: 0;
  }

  .#{$prefix}--no-gutter--end,
  .#{$prefix}--row.#{$prefix}--no-gutter--end [class*='#{$prefix}--col'] {
    padding-inline-end: 0;
  }
}

@function motion($name, $mode: productive, $easings: $easings) {
  @if map.has-key($easings, $name) {
    $easing: map.get($easings, $name);
    @if map.has-key($easing, $mode) {
      @return map.get($easing, $mode);
    } @else {
      @error 'Unable to find a mode for the easing #{$easing} called: #{$mode}.';
    }
  } @else {
    @error 'Unable to find an easing named #{$name} in our supported easings.';
  }
}

@each $type, $colors in $types {
  $border: map.get($colors, 'border');
  $background: map.get($colors, 'background');
  $color: map.get($colors, 'color');

  .#{$prefix}--annotation--#{$type} {
    border-color: $border;
  }

  .#{$prefix}--annotation--#{$type} > .#{$prefix}--annotation__label {
    background-color: $background;
    color: $color;
  }
}

@each $constraint in ('min', 'max') {
  .#{$prefix}--layout-constraint--#{$group}__#{$constraint}-#{$step} {
    @include custom-property.declaration(
      'layout-#{$group}-#{$property}-#{$constraint}',
      custom-property.get-var(
        'layout-#{$group}-#{$property}-#{$step}',
        $value
      )
    );
  }
}

@each $step, $value in $steps {
  :host(#{$host-selector}[#{$group}='#{$step}']) {
    @include custom-property.declaration(
      'layout-#{$group}-#{$property}-context',
      custom-property.get-var(
        'layout-#{$group}-#{$property}-#{$step}',
        $value
      )
    );
    @include custom-property.declaration(
      'layout-#{$group}-#{$property}',
      custom-property.get-var('layout-#{$group}-#{$property}-context')
    );
  }
}

@each $key, $value in $theme {
  @if $key == 'color-scheme' {
    @include custom-property.declaration($key, $value);

    color-scheme: custom-property.get-var($key, $value);
  } @else if meta.type-of($value) == color {
    @include custom-property.declaration($key, $value);
  }
}

@if meta.type-of($value) == map {
  $fallback: map.get($value, fallback);
  $theme-values: map.get($value, values);

  @each $theme-value in $theme-values {
    $value: map.get($theme-value, value);

    @if theme.matches(map.get($theme-value, theme), $theme) and
      meta.type-of($value) ==
      color
    {
      @include custom-property.declaration($key, $value);
    }
  }
}

&::before,
    &::after {
      position: absolute;
      display: block;
      block-size: 1px;
      content: '';
      inline-size: calc(100% - $spacing-05 - $spacing-05);
      margin-inline-start: $spacing-05;
      transition: background motion(standard, productive) $duration-fast-02;

      @media screen and (prefers-reduced-motion: reduce) {
        transition: none;
      }
    }

&::before,
    &::after {
      position: absolute;
      display: block;
      background: $layer-hover;
      block-size: 1px;
      content: '';
      inline-size: 100%;
      inset-inline-start: 0;
      transition: background motion(standard, productive) $duration-fast-02;

      @media screen and (prefers-reduced-motion: reduce) {
        transition: none;
      }
    }

@each $aspect-ratio in $aspect-ratios {
  $width: list.nth($aspect-ratio, 1);
  $height: list.nth($aspect-ratio, 2);

  .#{$prefix}--aspect-ratio--#{$width}x#{$height}::before {
    padding-block-start: math.percentage(math.div($height, $width));
  }
}

&::after {
  position: absolute;
  background: $focus;
  block-size: 1px;
  content: '';
  inline-size: convert.to-rem(12px);
  inset-block-end: 2px;
  opacity: 0;
  transition: opacity $duration-fast-01 motion(standard, productive);

  @media screen and (prefers-reduced-motion: reduce) {
    transition: none;
  }
}

&:disabled,
    &:hover:disabled,
    &:focus:disabled,
    &.#{$prefix}--btn--disabled,
    &.#{$prefix}--btn--disabled:hover,
    &.#{$prefix}--btn--disabled:focus {
      background: transparent;
      color: $text-disabled;
      outline: none;
    }

&:disabled,
    &:hover:disabled,
    &:focus:disabled,
    &.#{$prefix}--btn--disabled,
    &.#{$prefix}--btn--disabled:hover,
    &.#{$prefix}--btn--disabled:focus {
      border-color: transparent;
      background: transparent;
      color: $text-disabled;
      outline: none;
    }

&:disabled,
  &:hover:disabled,
  &:focus:disabled,
  &.#{$prefix}--btn--disabled,
  &.#{$prefix}--btn--disabled:hover,
  &.#{$prefix}--btn--disabled:focus {
    border-color: $button-disabled;
    background: $button-disabled;
    box-shadow: none;
    color: $text-on-color-disabled;
    cursor: not-allowed;
  }

@mixin bx--snippet {
  @include type-style('code-01');

  position: relative;
  background-color: $layer;
  inline-size: 100%;
  max-inline-size: convert.to-rem(768px);
  // Allow shrinking in grid/flex parents (e.g. Stack) so long pre content does not force layout width
  min-inline-size: 0;
}

@include layout.redefine-tokens(
  (
    size: (
      height: (
        xs: convert.to-rem(18px),
        sm: convert.to-rem(18px),
        md: convert.to-rem(24px),
        lg: convert.to-rem(24px),
        xl: convert.to-rem(24px),
      ),
    ),
  )
);

&::before {
  z-index: 0;
  border-radius: 0;
  block-size: 100%;
  border-block-end: convert.to-rem(1px) solid $border-inverse;
  border-block-start: convert.to-rem(1px) solid $border-inverse;
  box-shadow: inset 0 0 0 convert.to-rem(1px) $layer-hover;
  content: '';
  inline-size: 100%;
}

&.#{$prefix}--data-table--lg
      tr:not([data-child-row])
      td:not(.#{$prefix}--table-expand) {
      padding-block: $spacing-05 $spacing-05;

      &.#{$prefix}--table-column-menu {
        padding-block-start: $spacing-03;
      }

      &.#{$prefix}--table-column-checkbox:not(.#{$prefix}--table-column-radio) {
        padding-block-start: convert.to-rem(13px);
      }
    }

&::after {
  position: absolute;
  display: block;
  background-color: $link-primary;
  block-size: convert.to-rem(4px);
  content: '';
  inline-size: convert.to-rem(4px);
  inset-block-end: convert.to-rem(7px);
  inset-inline-start: 50%;
  transform: translateX(-50%);
}

button.#{$prefix}--dropdown-text {
  border: none;
  // button-reset mixin contradicts with cds--dropdown-text styles
  background: none;
  color: $text-primary;
  inline-size: 100%;
  text-align: start;

  &:focus {
    @include focus-outline('outline');
  }
}

&.#{$prefix}--tabs--contained .#{$prefix}--tab--overflow-nav-button {
  margin: 0;
  background-color: $layer-accent;
  inline-size: $spacing-09;

  &:hover {
    background-color: $layer-accent-hover;
  }

  &:active {
    background-color: $layer-accent-active;
  }
}

&:not(.#{$prefix}--tabs--contained)
      .#{$prefix}--tabs__nav-item:not(
        .#{$prefix}--tabs__nav-item--selected
      ):not(.#{$prefix}--tabs__nav-item--disabled):hover {
      border-block-end: $tab-underline-color-hover;
      color: $text-primary;
    }

&.#{$prefix}--tabs--contained
      .#{$prefix}--tabs__nav-item:not(
        .#{$prefix}--tabs__nav-item--selected
      ):not(.#{$prefix}--tabs__nav-item--disabled):not(
        .#{$prefix}--tabs__nav-item--hover-off
      ):hover {
      background-color: $layer-accent-hover;
      color: $text-primary;
    }

&.#{$prefix}--tabs--vertical
      .#{$prefix}--tabs__nav-item:not(
        .#{$prefix}--tabs__nav-item--selected
      ):not(.#{$prefix}--tabs__nav-item--disabled):not(
        .#{$prefix}--tabs__nav-item--hover-off
      ):hover {
      background-color: $layer-hover;
      box-shadow: inset 3px 0 0 0 $border-strong;
    }
